    def Check(self, request, context):
        """
        Process an authorization check request from Envoy.

        Args:
            request: CheckRequest containing the HTTP request attributes
            context: gRPC service context

        Returns:
            CheckResponse with OK status (allow) or denied status (reject)
        """
        try:
            return self._process_check(request, context)
        except Exception as e:
            logger.error(f"Unexpected error processing check request: {e}", exc_info=True)
            # Fail closed - deny on error
            return self._deny_response(
                status_code=500,
                body="Internal authorization error",
                headers={}
            )

    def _process_check(self, request, context):
        """Core check processing logic."""
        # Extract HTTP request attributes
        http_request = request.attributes.request.http
        headers = dict(http_request.headers)
        path = http_request.path
        method = http_request.method
        host = http_request.host
        protocol = http_request.protocol

        # Extract source information
        source = request.attributes.source
        source_address = ""
        if source and source.address and source.address.socket_address:
            source_address = source.address.socket_address.address

        logger.info(
            f"Auth check: method={method} path={path} host={host} "
            f"source={source_address} protocol={protocol}"
        )

        # Step 1: Header security - detect and handle Envoy header manipulation
        is_external = self._is_external_request(headers, source_address)

        if is_external:
            offending_headers = self._sanitizer.contains_envoy_internal_headers(headers)
            if offending_headers:
                logger.warning(
                    f"SECURITY: External request from {source_address} contains "
                    f"Envoy internal headers: {offending_headers}. "
                    f"Headers will be stripped."
                )
