                # This is more resilient than rejecting, as legitimate proxies
                # might inadvertently forward these headers

        # Step 2: Validate header names and values
        for name, value in headers.items():
            if not self._sanitizer.validate_header_name(name):
                logger.warning(
                    f"SECURITY: Invalid header name detected from {source_address}: {repr(name)}"
                )
